options.afterRender:
(function(){
  const API='http://localhost:2375';
  const SPRING='http://localhost:8080';
  // Containers ordered by importance; starred ones are "essential" (excluded from Stop All)
  const SVCS=[
    {name:'postgres-demo',        icon:'🐘',label:'PostgreSQL', essential:true},
    {name:'redis-demo',           icon:'🗄️',label:'Redis',       essential:true},
    {name:'kafka-demo',           icon:'📨',label:'Kafka',       essential:true},
    {name:'ollama',               icon:'🧠',label:'Ollama',      essential:false},
    {name:'keycloak',             icon:'🔐',label:'Keycloak',    essential:false},
    {name:'customerservice-lgtm', icon:'🔍',label:'LGTM',        essential:true},
    {name:'kafka-ui',             icon:'📋',label:'Kafka UI',    essential:false},
    {name:'redisinsight',         icon:'🔎',label:'RedisInsight',essential:false},
    {name:'redis-commander',      icon:'📟',label:'Redis Cmdr',  essential:false},
    {name:'pgadmin',              icon:'🛢️',label:'pgAdmin',     essential:false},
    {name:'pgweb',                icon:'🔬',label:'pgweb',       essential:false},
    {name:'sonarqube',            icon:'🔍',label:'SonarQube',   essential:false},
  ];

  const grid=document.getElementById('dc-grid');
  const msg=document.getElementById('dc-msg');

  function showMsg(text,color){
    msg.textContent=text; msg.style.color=color||'#94a3b8';
    if(color) setTimeout(()=>{msg.textContent='';msg.style.color='#94a3b8';},3000);
  }

  function render(states){
    grid.innerHTML=SVCS.map(s=>{
      const state=states[s.name];
      const up=state==='running', unk=!state;
      return `<div class="dc-card ${up?'is-up':unk?'':'is-down'}">
        <div class="dc-head">
          <span class="dc-icon">${s.icon}</span>
          <span class="dc-name" title="${s.name}">${s.label}</span>
          <span class="dc-badge ${up?'up':unk?'unk':'down'}">${up?'UP':unk?'—':'DOWN'}</span>
        </div>
        <div class="dc-btns">
          <button class="dc-btn dc-btn-stop" onclick="window._dc('${s.name}','stop')" ${!up?'disabled':''}>↓ Stop</button>
          <button class="dc-btn dc-btn-start" onclick="window._dc('${s.name}','start')" ${up?'disabled':''}>↑ Start</button>
        </div>
      </div>`;
    }).join('');
  }

  async function refresh(){
    try{
      const r=await fetch(`${API}/containers/json?all=true`);
      const list=await r.json();
      const states={};
      list.forEach(c=>{states[(c.Names[0]||'').replace('/','')]=c.State;});
      render(states);
    }catch(e){
      grid.innerHTML='<span class="dc-err">⚠ Docker API unreachable (localhost:2375)</span>';
    }
  }

  window._dc=async function(name,action){
    try{ await fetch(`${API}/containers/${name}/${action}`,{method:'POST'}); }catch(e){}
    showMsg(`${action==='stop'?'⏹':'▶'} ${name}…`);
    setTimeout(refresh,1500);
  };

  // Create a test customer
  document.getElementById('dc-create').onclick=async function(){
    this.disabled=true;
    const ts=Date.now();
    try{
      const r=await fetch(`${SPRING}/customers`,{
        method:'POST',
        headers:{'Content-Type':'application/json'},
        body:JSON.stringify({name:'Grafana User '+ts,email:'grafana'+ts+'@test.com'})
      });
      showMsg(r.ok?'✅ Customer created':'⚠ HTTP '+r.status, r.ok?'#22c55e':'#f59e0b');
    }catch(e){ showMsg('❌ API unreachable','#ef4444'); }
    setTimeout(()=>{document.getElementById('dc-create').disabled=false;},3000);
  };

  // Stop all non-essential containers
  document.getElementById('dc-stopall').onclick=async function(){
    this.disabled=true;
    const toStop=SVCS.filter(s=>!s.essential);
    showMsg('Stopping '+toStop.length+' containers…');
    await Promise.all(toStop.map(s=>fetch(`${API}/containers/${s.name}/stop`,{method:'POST'}).catch(()=>{})));
    setTimeout(()=>{refresh();this.disabled=false;},2000);
  };

  refresh();
  if(!window._dcTimer){ window._dcTimer=setInterval(refresh,5000); }
})();

(function(){
  const SPRING='http://localhost:8080';
  let running=false, sent=0, errors=0;

  const logEl=document.getElementById('tg-log');
  const startBtn=document.getElementById('tg-start');
  const stopBtn=document.getElementById('tg-stop');

  function log(msg,cls){
    const line=document.createElement('div');
    line.className=cls||'';
    line.textContent=msg;
    logEl.appendChild(line);
    logEl.scrollTop=logEl.scrollHeight;
    // Keep last 50 lines
    while(logEl.children.length>50) logEl.removeChild(logEl.firstChild);
  }

  startBtn.onclick=async function(){
    const count=parseInt(document.getElementById('tg-count').value)||10;
    const delay=parseInt(document.getElementById('tg-delay').value)||200;
    running=true; sent=0; errors=0;
    startBtn.disabled=true; stopBtn.disabled=false;
    log(`▶ Sending ${count} requests (${delay}ms delay)…`);

    for(let i=0;i<count && running;i++){
      const ts=Date.now();
      try{
        const r=await fetch(`${SPRING}/customers`,{
          method:'POST',
          headers:{'Content-Type':'application/json'},
          body:JSON.stringify({name:'Load User '+ts,email:'load'+ts+'@test.com'})
        });
        if(r.ok){ sent++; log(`✓ ${i+1}/${count} — 201 Created`,'tg-ok'); }
        else { errors++; log(`✗ ${i+1}/${count} — HTTP ${r.status}`,'tg-err'); }
      }catch(e){ errors++; log(`✗ ${i+1}/${count} — Error: ${e.message}`,'tg-err'); }
      if(delay>0 && i<count-1) await new Promise(r=>setTimeout(r,delay));
    }
    log(`Done. Sent: ${sent}, Errors: ${errors}`);
    running=false; startBtn.disabled=false; stopBtn.disabled=true;
  };

  stopBtn.onclick=function(){
    running=false;
    log('⏹ Stopped by user.');
    startBtn.disabled=false; stopBtn.disabled=true;
  };
})();
